// Get the response from the LLM
const response = $input.first().json;

// Debug: log what we received
console.log('LLM Response:', JSON.stringify(response, null, 2));

// The LLM Chain node outputs the response in different ways
let text = response.text || response.output || response.response || '';

// If still empty, check if the whole response is a string
if (!text && typeof response === 'string') {
  text = response;
}

if (!text) {
  throw new Error('No text found in LLM response. Keys: ' + Object.keys(response).join(', '));
}

// Clean up - remove markdown code blocks if present
let jsonStr = text.trim();
if (jsonStr.startsWith('```json')) {
  jsonStr = jsonStr.slice(7);
}
if (jsonStr.startsWith('```')) {
  jsonStr = jsonStr.slice(3);
}
if (jsonStr.endsWith('```')) {
  jsonStr = jsonStr.slice(0, -3);
}
jsonStr = jsonStr.trim();

// Parse JSON
let parsed;
try {
  parsed = JSON.parse(jsonStr);
} catch (e) {
  throw new Error('Failed to parse JSON. Raw text: ' + text);
}

// Get original file info
const triggerData = $('📥 Watch Receipts Folder').first().json;

// Build output with null-safe values (Google Sheets doesn't like null)
const output = {
  Date: parsed.date || '',
  Vendor: parsed.vendor || '',
  Category: parsed.category || '',
  Description: parsed.description || '',
  Subtotal: parseFloat(parsed.subtotal) || 0,
  Tax: parseFloat(parsed.tax) || 0,
  Tip: parseFloat(parsed.tip) || 0,
  Total: parseFloat(parsed.total) || 0,
  'Payment Method': parsed.payment_method || '',
  'Transaction ID': parsed.transaction_id || '',
  'Receipt Link': triggerData.webViewLink || `https://drive.google.com/file/d/${triggerData.id}/view`,
  'Processed At': new Date().toISOString(),
  Confidence: parsed.confidence || 'low'
};

return [{ json: output }];
